15	const BASE_PREMIUM: Record<string, number> = {
16	  sword: 100,
17	  amulet: 60,
18	  staff: 80,
19	};
20	
21	const FIRST_INSURANCE_MULTIPLIER = 1.1;
22	const PROCESSING_FEE = 5;
23	const ROUNDING_PRECISION = 6;
24	
25	const quotePremium = (items: Item[]): number => {
26	  let total = 0;
27	  for (const item of items) {
28	    const base = BASE_PREMIUM[item.type];
29	    total += base * FIRST_INSURANCE_MULTIPLIER;
30	  }
31	  const totalWithFee = total + PROCESSING_FEE;
32	  return Math.ceil(Number(totalWithFee.toFixed(ROUNDING_PRECISION)));
33	};
34	
35	export const runScenario = (scenario: Scenario): { results: { premium: number }[] } => {
36	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
37	  return { results };
38	};
